import { IMessageEvent, MessageEvent } from '@nitrots/nitro-renderer/src/core';
import { HotelAlertParser } from '@nitrots/nitro-renderer/src/nitro/communication/messages/parser/HotelAlertParser';

export class HotelAlertEvent extends MessageEvent implements IMessageEvent {
    constructor(callback: Function) {
        super(callback, HotelAlertParser);
        //console.log('[🏨] HotelAlertEvent wired.');
    }

    public getParser(): HotelAlertParser {
        return this.parser as HotelAlertParser;
    }
}
